INSERT INTO public.news (slug, title, title_en, title_hy, excerpt, excerpt_en, excerpt_hy, category, category_en, category_hy, body, body_en, body_hy, image_url, published_at, is_published, sort_order) VALUES ('red-dot-and-big-see-design-award', 'Red Dot Design Award & BIG SEE Product Design Award 2026: SMEG recognized for excellence', 'Red Dot Design Award & BIG SEE Product Design Award 2026: SMEG recognized for excellence', NULL, 'SMEG wins the Red Dot Design Award and the BIG SEE Product Design Award 2026, celebrating excellence in design, innovation, and functionality, and highlighting the excellence of Italian home appliance design.', 'SMEG wins the Red Dot Design Award and the BIG SEE Product Design Award 2026, celebrating excellence in design, innovation, and functionality, and highlighting the excellence of Italian home appliance design.', NULL, 'Awards', 'Awards', NULL, 'The induction hob with integrated hood from the Isola collection, Alta Pro Range, wins two of the most prestigious international design awards, adding to SMEG’s growing portfolio of global awards.

The Red Dot Design Award and the BIG SEE Product Design Award are internationally recognized prizes celebrating excellence in design, innovation and functionality. These prestigious 2026 awards confirm SMEG’s ability to stand out on the global stage by combining advanced technology, sustainability and distinctive style. Evaluated by international juries of design experts, both awards recognize products that excel in quality, aesthetics and forward-thinking solutions. These achievements further strengthen SMEG’s leadership in design, innovation and technological excellence.

Scroll SMEG’s design success continues This latest recognition adds to the brand’s already prestigious awards portfolio, including the iF Design Award, Design Intelligence Award, and Good Design Award, reinforcing SMEG’s position as a benchmark for excellence in design applied to home appliances.  ISOLA hob: SMEG design shapes space A dialogue between technology, architecture, and light. Timeless materials and tactile contrasts come together to create a contemporary, sensorial elegance.

The motorized downdraft hood ascends like a silent performance, the LED frame glows like a halo, and the 5” TFT display illuminates with intuitive clarity. GenX technology refines every gesture: precise cooking, gentle sound, effortless transitions.', 'The induction hob with integrated hood from the Isola collection, Alta Pro Range, wins two of the most prestigious international design awards, adding to SMEG’s growing portfolio of global awards.

