INSERT INTO public.news (slug, title, title_en, title_hy, excerpt, excerpt_en, excerpt_hy, category, category_en, category_hy, body, body_en, body_hy, image_url, published_at, is_published, sort_order) VALUES ('if-design-award-2026', 'iF Design Award 2026: SMEG recognized for design and technology excellence', 'iF Design Award 2026: SMEG recognized for design and technology excellence', NULL, 'SMEG wins the iF Design Award 2026 thanks to solutions that combine attention to detail and innovation.', 'SMEG wins the iF Design Award 2026 thanks to solutions that combine attention to detail and innovation.', NULL, 'Awards', 'Awards', NULL, 'SMEG continues to stand out on the international design scene, securing the prestigious award for two products: the SMEG digital kitchen scale and the Isola collection, Alta Pro Range, hob with integrated hood.

Organized by the iF International Forum Design GmbH, the award is one of the world’s most recognized seals of design excellence, celebrating innovation, functionality and aesthetic quality across industries. The 2026 recognition once again confirms SMEG’s ability to blend advanced technology with distinctive Italian design.

SMEG digital scale: accuracy for everyday cooking An essential tool for everyday cooking, the SMEG Digital Kitchen Scale has received the iF Design Award 2026 for its refined design and user-focused functionality.

Designed by deepdesign studio by Raffaella Mangiarotti and Matteo Bazzicalupo, it complements SMEG’s small appliance collection and is available in three matte finishes: white, black and emerald green. Premium details, including a brushed aluminum panel, aluminum buttons and a removable stainless-steel bowl, enhance its distinctive aesthetic.

COMING SOON ISOLA hob: SMEG design shapes space The Isola Collection hob with integrated hood, created in collaboration with Stefano Boeri Interiors, has been honored with the iF Design Award 2026.

Redefining the role of the hob and extraction system in contemporary kitchens, Isola transforms the appliance into an architectural feature. Rounded shapes and the careful use of light create harmony and enhance everyday interaction.

Smeg S.p.A - Via Leonardo da Vinci, 4 42016 Guastalla (RE) Italy

