INSERT INTO public.news (slug, title, title_en, title_hy, excerpt, excerpt_en, excerpt_hy, category, category_en, category_hy, body, body_en, body_hy, image_url, published_at, is_published, sort_order) VALUES ('design-intelligence-award-isola', 'Isola receives the 2025 Design Intelligence Award', 'Isola receives the 2025 Design Intelligence Award', NULL, 'The Isola project, developed in collaboration with Stefano Boeri Interiors, wins the 2025 Design Intelligence Award for its induction hob with integrated hood. Innovation, design, and a vision of the future.', 'The Isola project, developed in collaboration with Stefano Boeri Interiors, wins the 2025 Design Intelligence Award for its induction hob with integrated hood. Innovation, design, and a vision of the future.', NULL, 'Awards', 'Awards', NULL, 'Technological and design innovation, the impact of the proposed solutions, and the ability to anticipate the future: these are the values that have led the induction hob with integrated hood from the Isola project to win the 2025 Design Intelligence Award.  A new way of experiencing the kitchen. Within the Isola project, the induction hob with integrated hood, designed in collaboration with Stefano Boeri Interiors, wins the 2025 Design Intelligence Award in the Industry category.

A prestigious international recognition that highlights the fusion of technological and design innovation, as well as the project’s ability to anticipate new scenarios for contemporary living.

Presented as a concept at Eurocucina 2024 and subsequently developed, the Isola range today receives an important confirmation of its value and is set to arrive in stores and online starting in 2026.

Inspired by classic Smeg design yet projected into the future, Isola is a collection of induction hobs, with and without integrated hood, and extraction systems that redefines kitchen aesthetics by making innovation perceptible.

Smeg S.p.A - Via Leonardo da Vinci, 4 42016 Guastalla (RE) Italy

Phone +39 0522 821 1 Fax +39 0522 821 452 Email [email protected]', 'Technological and design innovation, the impact of the proposed solutions, and the ability to anticipate the future: these are the values that have led the induction hob with integrated hood from the Isola project to win the 2025 Design Intelligence Award.  A new way of experiencing the kitchen. Within the Isola project, the induction hob with integrated hood, designed in collaboration with Stefano Boeri Interiors, wins the 2025 Design Intelligence Award in the Industry category.

A prestigious international recognition that highlights the fusion of technological and design innovation, as well as the project’s ability to anticipate new scenarios for contemporary living.

Presented as a concept at Eurocucina 2024 and subsequently developed, the Isola range today receives an important confirmation of its value and is set to arrive in stores and online starting in 2026.

