INSERT INTO public.news (slug, title, title_en, title_hy, excerpt, excerpt_en, excerpt_hy, category, category_en, category_hy, body, body_en, body_hy, image_url, published_at, is_published, sort_order) VALUES ('new-york-design-week-2025', 'Smeg USA at BIG ITALY DESIGN NYC 2025', 'Smeg USA at BIG ITALY DESIGN NYC 2025', NULL, 'Smeg’s blend of Italian artistry and innovation at BIG ITALY DESIGN NYC 2025, a tribute to design and contemporary lifestyle.', 'Smeg’s blend of Italian artistry and innovation at BIG ITALY DESIGN NYC 2025, a tribute to design and contemporary lifestyle.', NULL, 'Corporate', 'Corporate', NULL, 'Casa Italia – BIG ITALY New York 2025 Starting May 14, 2025, Smeg USA will participate in Casa Italia, an exclusive exhibition held at the Italian Trade Agency headquarters at 33 East 67th Street, a historic residence formerly owned by Jacqueline Kennedy.

In this prestigious setting, Smeg will showcase a selection of products representing Made in Italy excellence in appliance design, including cookers, iconic colorful refrigerators, and small domestic appliances.

From May 13 to 15, 2025, Smeg will also be a partner of Italy on Madison, a cultural initiative that transforms Madison Avenue into a showcase of Italian design, craftsmanship, and lifestyle.

The program features public events, talks, tastings, immersive experiences and lifestyle moments – including show cooking sessions, meetings with Italian chefs, and design-themed installations.

Through these initiatives, Smeg strengthens its presence in the United States and enhances the dialogue between culture, aesthetics, and innovation.

Participation in New York Design Week confirms the brand’s role as a global ambassador of Italian design.

Smeg S.p.A - Via Leonardo da Vinci, 4 42016 Guastalla (RE) Italy

