INSERT INTO public.news (slug, title, title_en, title_hy, excerpt, excerpt_en, excerpt_hy, category, category_en, category_hy, body, body_en, body_hy, image_url, published_at, is_published, sort_order) VALUES ('smeg-at-milan-design-week-2025', 'Smeg at Milan Design Week 2025', 'Smeg at Milan Design Week 2025', NULL, 'Smeg at Milan Design Week 2025 - Find out the latest news from Smeg.com', 'Smeg at Milan Design Week 2025 - Find out the latest news from Smeg.com', NULL, 'Events', 'Events', NULL, 'On the occasion of Milan Design Week 2025, Smeg presents a selection of projects and collaborations that tell the brand''s vision: a unique balance between heritage and contemporaneity, technology and beauty, functionality and the culture of design.

Design Holds Memories, between past and present Inside the Flagship Store on Via della Moscova, Design Holds Memories comes to life, an interdisciplinary project born from the collaboration with Istituto Marangoni Milano Design. The initiative involves young talents who, starting from the iconic FAB28 refrigerator, explore the relationship between objects and memory, shaping an immersive experience between the past and present.

Discover where to find Smeg at Fuori Salone 1. Design Holds Memories Smeg Flagship Store - Via della Moscova, 58, Milan. April 7th: 10 am – 7 pm | April 8th – 11th: 10 am – 9 pm | April 12th – 13th: 10 am –7 pm         Discover more

2. Kaikado 150, Book Presentation ERG MEDIA - Via Bernardino Luini 12 April 9th – 13th Discover more

3. Be up – where architecture meets infinity Simone Micheli – University of Milan (Statale) April 7 th –17 th Discover more

