INSERT INTO public.news (slug, title, title_en, title_hy, excerpt, excerpt_en, excerpt_hy, category, category_en, category_hy, body, body_en, body_hy, image_url, published_at, is_published, sort_order) VALUES ('smeg-attends-eurocucina-2024', 'SMEG towards new horizons at Eurocucina 2024', 'SMEG towards new horizons at Eurocucina 2024', NULL, 'Smeg attends Eurocucina 2024 - Find out the latest news from Smeg.com', 'Smeg attends Eurocucina 2024 - Find out the latest news from Smeg.com', NULL, 'Events', 'Events', NULL, 'The Salone del Mobile is back and Smeg exhibits at Eurocucina 2024 in Hall 4, Stand D01-D03.

