INSERT INTO public.news (slug, title, title_en, title_hy, excerpt, excerpt_en, excerpt_hy, category, category_en, category_hy, body, body_en, body_hy, image_url, published_at, is_published, sort_order) VALUES ('smeg-bcc-full-automatic-coffee-machine-earns-design-award-2023', 'SMEG RECOGNIZED WINNER OF DESIGNEUROPA AWARD 2023', 'SMEG RECOGNIZED WINNER OF DESIGNEUROPA AWARD 2023', NULL, 'Smeg is the winner in the Industry category for the 2023 edition with the BCC Full Automatic coffee machine.', 'Smeg is the winner in the Industry category for the 2023 edition with the BCC Full Automatic coffee machine.', NULL, 'Awards', 'Awards', NULL, 'BCC Full Automatic coffee machine as an example of distinctive design.

The DesignEuropa Awards are now in their fourth year. Organised by the European Union Intellectual Property Office (EUIPO), the DesignEuropa awards recognise and reward great products and designers in the field of industrial design. Smeg is the winner in the Industry category for the 2023 edition with the BCC Full Automatic coffee machine. The finalists stood out from almost 700 applicants for setting new standards in design, as well as prioritising sustainability and social impact.

The BCC machine represents a perfect synthesis of Smeg''s vision: a product with an iconic design that conceals advanced technology. It is the dialogue between technology and design that makes the product empathetic and user-friendly, so that the user can use it at any time of day. Discover all the products Smeg participated together with all the other finalists at the award ceremony in Berlin on 5th September 2023, with the aim emphasising the importance of intellectual property, for which EUIPO stands. Discover the BCC range: Filters Active: Reset filters Show more', 'BCC Full Automatic coffee machine as an example of distinctive design.

The DesignEuropa Awards are now in their fourth year. Organised by the European Union Intellectual Property Office (EUIPO), the DesignEuropa awards recognise and reward great products and designers in the field of industrial design. Smeg is the winner in the Industry category for the 2023 edition with the BCC Full Automatic coffee machine. The finalists stood out from almost 700 applicants for setting new standards in design, as well as prioritising sustainability and social impact.

The BCC machine represents a perfect synthesis of Smeg''s vision: a product with an iconic design that conceals advanced technology. It is the dialogue between technology and design that makes the product empathetic and user-friendly, so that the user can use it at any time of day. Discover all the products Smeg participated together with all the other finalists at the award ceremony in Berlin on 5th September 2023, with the aim emphasising the importance of intellectual property, for which EUIPO stands. Discover the BCC range: Filters Active: Reset filters Show more', NULL, 'https://www.smeg.com/binaries/content/gallery/smeg/stories/dea_bcc_960x690.jpg/dea_bcc_960x690.jpg/brx%3ApostcardDeskLarge', '2023-06-15T10:00:00Z', true, 100);
INSERT INTO public.news (slug, title, title_en, title_hy, excerpt, excerpt_en, excerpt_hy, category, category_en, category_hy, body, body_en, body_hy, image_url, published_at, is_published, sort_order) VALUES ('storing-wine-at-home-with-smeg-wine-coolers', 'STORING WINE AT HOME WITH SMEG WINE COOLERS', 'STORING WINE AT HOME WITH SMEG WINE COOLERS', NULL, 'Discover more about Smeg wine coolers.', 'Discover more about Smeg wine coolers.', NULL, 'Products', 'Products', NULL, 'When it comes to dinner with friends, receiving a bottle of good wine is among the most appreciated gestures by the host, whether he is an enthusiast, a true wine connoisseur or an occasional consumer.

Wine, in fact, is synonymous with conviviality and has always belonged to the Italian tradition of both food and wine and hospitality.

Properly storing wine at home, however, is not child''s play if one does not take into account the basic precautions for perfect storage over a long period of time.

LIGHT For best conservation, bottles should be kept away from sources of light and heat.

HUMIDITY The humidity level considered optimal for long-term wine storage ranges from 60 to 80%.

VIBRATIONS The absence of vibrations favours the proper storage of wine. It is therefore necessary to store bottles on a stable support.

TEMPERATURE To appreciate wine at its best, it is essential to store and serve it at the correct temperature.

What temperature is the right one to serve wine? Choosing the correct serving temperature for wine is essential to fully appreciate it during a meal, an aperitif or an after-dinner drink. But how to choose? There are some good rules for serving wine, which must also take into account personal taste and the variables linked to the environment.

Having the right tools is essential for storing and serving wine at its best. Choosing the right glass, for example, allows all the aromas and perfumes to be released for a perfect match with food.

Storing bottles in a home cellar, moreover, is the solution for keeping them at the right temperature.', 'When it comes to dinner with friends, receiving a bottle of good wine is among the most appreciated gestures by the host, whether he is an enthusiast, a true wine connoisseur or an occasional consumer.

