INSERT INTO public.news (slug, title, title_en, title_hy, excerpt, excerpt_en, excerpt_hy, category, category_en, category_hy, body, body_en, body_hy, image_url, published_at, is_published, sort_order) VALUES ('snoopy-2022', 'THE RETURN OF SNOOPY', 'THE RETURN OF SNOOPY', NULL, 'Smeg collaborates once more with iconic comic strip Peanuts to create a unique FAB10 fridge featuring beloved characters Snoopy and Woodstock.', 'Smeg collaborates once more with iconic comic strip Peanuts to create a unique FAB10 fridge featuring beloved characters Snoopy and Woodstock.', NULL, 'Events', 'Events', NULL, 'Two years after the success of the limited edition FAB10 refrigerator that celebrated the 70th Anniversary of Peanuts, Smeg launches a new mini-refrigerator FAB10 to add to the range of colorful domestic mini-fridges.

ORIGINAL ILLUSTRATION Once again, the Peanuts characters, beloved around the world by adults and children alike and known for their indelible mark on popular culture, are the primary feature of Smeg’s iconic FAB refrigerator, an emblem of style and design.

The reference product for this second edition is the FAB10 model, the 1950s style family mini-refrigerator, on which Snoopy, the well-known pet beagle of Charlie Brown, stands out along with his best bird friend, Woodstock.

The white background of the refrigerator is inspired by the white sheet of paper on which Charles Schulz''s drew his comic strip.

The new FAB10 refrigerator, perfectly combining Smeg''s iconic design with the beloved Peanuts characters, is ready to be welcomed home by fans of all ages.

Smeg S.p.A - Via Leonardo da Vinci, 4 42016 Guastalla (RE) Italy

