INSERT INTO public.news (slug, title, title_en, title_hy, excerpt, excerpt_en, excerpt_hy, category, category_en, category_hy, body, body_en, body_hy, image_url, published_at, is_published, sort_order) VALUES ('eurocucina-2022', 'SMEG ATTENDS EUROCUCINA 2022', 'SMEG ATTENDS EUROCUCINA 2022', NULL, 'The 2022 edition of the Salone del Mobile at Rho Fiera Milano opens from 7 to 12 June. Smeg will be present with all the new products at stand M22 - M28 in Hall 11.', 'The 2022 edition of the Salone del Mobile at Rho Fiera Milano opens from 7 to 12 June. Smeg will be present with all the new products at stand M22 - M28 in Hall 11.', NULL, 'Corporate', 'Corporate', NULL, 'Among the novelties on display is the Galileo project, the range of ovens that revolutionizes the cooking experience thanks to the combination of traditional, steam and microwave cooking functions. Omnichef is the spearhead of the project: three technologies in a single oven, with professional algorithms and special functions to satisfy every need.

The attention to detail and made in Italy design are reflected in new aesthetic finishes for the Linea and Classica collections: the elegant Neptune Grey and the contemporary Black Matt.

Among the novelties on display in the stand is the Area induction hob, equipped with a shiny ceramic glass surface in black or silver version with screen printing under the glass and without pre-set cooking areas, to ensure maximum flexibility of use on a surface of 90 cm.

FAB refrigerators are a must: 9 brand new matt colors capture the attention with special finishes and the ever-present sinuous shapes of retro inspiration.

Among the novelties presented, also the restyling of the colorful Portofino cookers, a tribute to the exclusive Ligurian village. With renewed technology and aesthetics, they are exhibited in 90, 120 and the new 150 cm sizes.

Technology and design are also the leitmotif of the collaboration between Smeg and leading brands such as Dolce and Gabbana and Veuve Clicquot

The timeless kitchen created in collaboration with Dolce and Gabbana.

The FAB10 and FAB28 Smeg refrigerators dressed in the special edition yellow Veuve Clicquot.

Smeg is pleased to welcome all visitors to its stand to share the news for 2022', 'Among the novelties on display is the Galileo project, the range of ovens that revolutionizes the cooking experience thanks to the combination of traditional, steam and microwave cooking functions. Omnichef is the spearhead of the project: three technologies in a single oven, with professional algorithms and special functions to satisfy every need.

