INSERT INTO public.news (slug, title, title_en, title_hy, excerpt, excerpt_en, excerpt_hy, category, category_en, category_hy, body, body_en, body_hy, image_url, published_at, is_published, sort_order) VALUES ('frimed-acquisition', 'SMEG ANNOUNCES THE ACQUISITION OF FRIMED', 'SMEG ANNOUNCES THE ACQUISITION OF FRIMED', NULL, 'Smeg enters the share capital of Frimed as majority shareholder', 'Smeg enters the share capital of Frimed as majority shareholder', NULL, 'Events', 'Events', NULL, 'With its know-how deriving from over 70 years of experience in the production of Made in Italy design household appliances, Smeg announces the entry as majority shareholder in the capital of FRIMED, a company operating in the medical refrigeration sector.

FRIMED, founded in 1997 and based in Chieri (TO), has established itself in the design of professional equipment for the hospital, industrial, biomedical and pharmaceutical sectors, thanks to a profound commitment to scientific research and innovation.

THE AIM OF THE ACQUISITION The strategic objective of the acquisition is to consolidate Smeg''s presence in the medical sector and will lead to the sharing of the know-how of the two companies, for the creation of solutions with high technological value and pursuing a sustainable innovation process.

Smeg S.p.A - Via Leonardo da Vinci, 4 42016 Guastalla (RE) Italy

Phone +39 0522 821 1 Fax +39 0522 821 452 Email [email protected]', 'With its know-how deriving from over 70 years of experience in the production of Made in Italy design household appliances, Smeg announces the entry as majority shareholder in the capital of FRIMED, a company operating in the medical refrigeration sector.

FRIMED, founded in 1997 and based in Chieri (TO), has established itself in the design of professional equipment for the hospital, industrial, biomedical and pharmaceutical sectors, thanks to a profound commitment to scientific research and innovation.

