INSERT INTO public.news (slug, title, title_en, title_hy, excerpt, excerpt_en, excerpt_hy, category, category_en, category_hy, body, body_en, body_hy, image_url, published_at, is_published, sort_order) VALUES ('coffee-machines-prizes-awards-2020', 'Award-winning internationally designed coffee machines', 'Award-winning internationally designed coffee machines', NULL, 'Smeg coffee machines have won Red Dot and Good Design awards for their innovation and iconic 50s-inspired design.', 'Smeg coffee machines have won Red Dot and Good Design awards for their innovation and iconic 50s-inspired design.', NULL, 'Corporate', 'Corporate', NULL, 'Awards are proof of excellence and are achieved when the ideas and work carried out by designers are recognised by the public, by insiders, by the world of designers, architects, and communicators. As a result, the awards become a vehicle for promoting innovation and trends.

Some of the most important international awards include the world-famous Good Design Award and the Red Dot Design Award, which Smeg has won several times, combining painstaking attention to product design with state-of-the-art technology.

The Red Dot Design Award is assigned each year in Germany to highlight the mix of design and business excellence in the fields of product design, communication design and design concept. Instead, the Good Design Award was founded in Chicago by Charles and Ray Eames, Eero Saarinen and MoMA curator Edgar Kaufmann Jr. It has rewarded excellence in design worldwide since 1950 and the awards are conferred annually by the Chicago Athenaeum.

Among Smeg''s small household appliances, many products have won these awards since 2015: coffee machines, milk frothers, coffee grinders.

The designers of the award-winning 50s Style small appliance range are, together with Smeg, Raffaella Mangiarotti and Matteo Bazzicalupo from the deepdesign® studio.

"The idea was to have objects that would sit on the kitchen countertop and become as if they were your friends. That is, turning objects into small subjects."

The ECF02 Manual Espresso Machine Winner of the Good Design Award ECF02 is the Made in Italy manual espresso machine that guarantees the best result for an excellent espresso coffee.

The DCF02 Filter Coffee Machine Winner of the Red Dot Design Award Designed to evoke the 1950''s, it is perfect for sharing a great international breakfast with your family or friends.

The BCC01 Automatic Espresso Machine Winner of the Good Design Award BCC01 grinds coffee beans that preserve the fragrance of your blend and makes the coffee experience unique, in every sense.

The MFF11 Milk Frother wins Good Design Awards With its steel body and iconic design, it has 6 pre-set functions and an induction heating system, ideal for creating your favourite milk recipe: cappuccino, hot milk, hot chocolate...', 'Awards are proof of excellence and are achieved when the ideas and work carried out by designers are recognised by the public, by insiders, by the world of designers, architects, and communicators. As a result, the awards become a vehicle for promoting innovation and trends.

